('Epinephrine', 'Allergy', 'Epinephrine is a sympathomimetic used for severe allergic reactions (anaphylaxis). It stimulates alpha and beta receptors.', '0.3-0.5mg IM, auto-injector 0.15-0.3mg', 'Tachycardia, palpitations, hypertension, anxiety, tremor, headache, arrhythmias', 4.9, '$$$', 'Prescription only', 'Mylan', 'Sympathomimetic', 'C', 'Room temperature 20-25°C', '2-3 min', '1-2 min', '15-30 min', 'Hepatic', 'Renal', 7654, 'Beta-blockers,Digoxin,MAOIs,TCAs', 'Cardiac arrhythmias, hypertension, use only for severe reactions', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Hydrocortisone', 'Allergy', 'Hydrocortisone is a corticosteroid used for allergic and inflammatory conditions. It has anti-inflammatory and immunosuppressive properties.', '1% cream applied 2-4 times daily, 10-40mg oral, 100mg IV for anaphylaxis', 'Topical: skin irritation, atrophy, hypopigmentation. Systemic: weight gain, immunosuppression', 4.4, '$$', 'Over-the-counter', 'Pfizer', 'Corticosteroid', 'C', 'Room temperature 20-25°C', '1.5-2 hours', '1-2 hours', '4-6 hours', 'Hepatic', 'Renal', 4321, 'NSAIDs,Diuretics,Antidiabetics,Anticonvulsants', 'Immunosuppression, adrenal suppression, use lowest dose', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
