('Fluoxetine', 'Psychiatry', 'Fluoxetine is an SSRI used for depression, OCD, bulimia, and PMDD. It increases serotonin levels by inhibiting reuptake.', '20-80mg once daily', 'Nausea, insomnia, sexual dysfunction, weight changes, drowsiness, dry mouth', 4.6, '$$$', 'Prescription only', 'Eli Lilly', 'SSRI', 'C', 'Room temperature 20-25°C', '1-3 days', '1-2 weeks', '24 hours', 'Hepatic', 'Renal', 8765, 'MAOIs,NSAIDs,Triptans,Warfarin,Alcohol', 'Serotonin syndrome, suicidal risk, sexual dysfunction, withdrawal', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Sertraline', 'Psychiatry', 'Sertraline is an SSRI used for depression, anxiety, OCD, and PTSD. It increases serotonin levels in the brain.', '50-200mg once daily', 'Nausea, insomnia, sexual dysfunction, weight gain, dry mouth, diarrhea', 4.6, '$$$', 'Prescription only', 'Pfizer', 'SSRI', 'C', 'Room temperature 20-25°C', '26 hours', '1-2 hours', '24 hours', 'Hepatic', 'Renal', 7654, 'MAOIs,NSAIDs,Triptans,Warfarin,Alcohol', 'Serotonin syndrome, suicidal risk, sexual dysfunction, withdrawal', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Paroxetine', 'Psychiatry', 'Paroxetine is an SSRI used for depression, anxiety, PTSD, and OCD. It is more sedating than other SSRIs.', '20-50mg once daily', 'Nausea, insomnia, sexual dysfunction, weight gain, drowsiness, withdrawal syndrome', 4.4, '$$$', 'Prescription only', 'GlaxoSmithKline', 'SSRI', 'D', 'Room temperature 20-25°C', '21 hours', '1-2 hours', '24 hours', 'Hepatic', 'Renal', 6543, 'MAOIs,NSAIDs,Triptans,Warfarin,Alcohol', 'Serotonin syndrome, suicidal risk, sexual dysfunction, significant withdrawal', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Citalopram', 'Psychiatry', 'Citalopram is an SSRI used for depression. It increases serotonin levels with minimal drug interactions.', '20-40mg once daily, max 40mg (60mg for severe)', 'Nausea, insomnia, sexual dysfunction, weight gain, dry mouth, QT prolongation', 4.5, '$$$', 'Prescription only', 'Lundbeck', 'SSRI', 'C', 'Room temperature 20-25°C', '35 hours', '1-2 weeks', '24 hours', 'Hepatic', 'Renal', 5432, 'MAOIs,NSAIDs,Triptans,Warfarin,Alcohol', 'Serotonin syndrome, QT prolongation, suicidal risk, sexual dysfunction', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Escitalopram', 'Psychiatry', 'Escitalopram is an SSRI used for depression and anxiety. It is the active enantiomer of citalopram.', '10-20mg once daily', 'Nausea, insomnia, sexual dysfunction, weight gain, dry mouth, QT prolongation', 4.7, '$$$', 'Prescription only', 'Lundbeck', 'SSRI', 'C', 'Room temperature 20-25°C', '27-32 hours', '1-2 weeks', '24 hours', 'Hepatic', 'Renal', 8765, 'MAOIs,NSAIDs,Triptans,Warfarin,Alcohol', 'Serotonin syndrome, QT prolongation, suicidal risk, sexual dysfunction', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Duloxetine', 'Psychiatry', 'Duloxetine is an SNRI used for depression, anxiety, and chronic pain. It increases serotonin and norepinephrine levels.', '30-60mg once daily, max 120mg', 'Nausea, insomnia, dry mouth, sexual dysfunction, weight gain, hepatotoxicity', 4.6, '$$$$', 'Prescription only', 'Eli Lilly', 'SNRI', 'C', 'Room temperature 20-25°C', '12 hours', '1-2 weeks', '24 hours', 'Hepatic', 'Renal', 6543, 'MAOIs,NSAIDs,Triptans,Warfarin,Alcohol', 'Serotonin syndrome, hepatotoxicity, suicidal risk, withdrawal', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Venlafaxine', 'Psychiatry', 'Venlafaxine is an SNRI used for depression, anxiety, and panic disorder. It increases serotonin and norepinephrine levels.', '37.5-225mg daily, extended release once daily', 'Nausea, insomnia, sexual dysfunction, weight gain, hypertension, withdrawal', 4.5, '$$$$', 'Prescription only', 'Pfizer', 'SNRI', 'C', 'Room temperature 20-25°C', '5-11 hours', '1-2 weeks', '24 hours', 'Hepatic', 'Renal', 5432, 'MAOIs,NSAIDs,Triptans,Warfarin,Alcohol', 'Serotonin syndrome, hypertension, suicidal risk, significant withdrawal', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Bupropion', 'Psychiatry', 'Bupropion is an antidepressant used for depression and smoking cessation. It inhibits dopamine and norepinephrine reuptake.', '100-150mg 3 times daily, extended release 150-300mg once daily', 'Insomnia, agitation, seizures, dry mouth, weight loss, headache', 4.7, '$$$', 'Prescription only', 'GlaxoSmithKline', 'Antidepressant', 'C', 'Room temperature 20-25°C', '20-25 hours', '1-2 weeks', '24 hours', 'Hepatic', 'Renal', 7654, 'MAOIs,Antipsychotics,CYP2D6 inhibitors,Alcohol', 'Seizure risk, agitation, insomnia, avoid in eating disorders', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Mirtazapine', 'Psychiatry', 'Mirtazapine is an antidepressant used for depression. It increases serotonin and norepinephrine through alpha-2 antagonism.', '15-45mg once daily at bedtime', 'Sedation, weight gain, increased appetite, dizziness, dry mouth', 4.5, '$$$', 'Prescription only', 'Merck', 'Antidepressant', 'C', 'Room temperature 20-25°C', '20-40 hours', '1-2 weeks', '24 hours', 'Hepatic', 'Renal', 5432, 'MAOIs,CNS depressants,Alcohol,Benzodiazepines', 'Sedation, weight gain, suicidal risk, monitor cholesterol', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Quetiapine', 'Psychiatry', 'Quetiapine is an atypical antipsychotic used for schizophrenia, bipolar disorder, and depression. It blocks dopamine and serotonin receptors.', '25-800mg daily, 50-300mg for bipolar depression', 'Sedation, weight gain, hyperlipidemia, hyperglycemia, hypotension, EPS (low)', 4.5, '$$$$', 'Prescription only', 'AstraZeneca', 'Atypical Antipsychotic', 'C', 'Room temperature 20-25°C', '6-9 hours', '1-2 hours', '24 hours', 'Hepatic', 'Renal', 6543, 'CYP3A4 inhibitors,CYP3A4 inducers,CNS depressants', 'Weight gain, hyperlipidemia, hyperglycemia, sedation, monitor metabolic parameters', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Risperidone', 'Psychiatry', 'Risperidone is an atypical antipsychotic used for schizophrenia, bipolar mania, and irritability in autism. It blocks dopamine and serotonin receptors.', '1-6mg daily, 0.5-3mg for elderly', 'EPS, weight gain, hyperprolactinemia, sedation, orthostatic hypotension', 4.4, '$$$$', 'Prescription only', 'Janssen', 'Atypical Antipsychotic', 'C', 'Room temperature 20-25°C', '3-20 hours', '1-2 hours', '24 hours', 'Hepatic', 'Renal', 5432, 'CYP3A4 inhibitors,CYP2D6 inhibitors,CNS depressants', 'EPS, hyperprolactinemia, weight gain, monitor metabolic parameters', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Olanzapine', 'Psychiatry', 'Olanzapine is an atypical antipsychotic used for schizophrenia and bipolar disorder. It blocks dopamine and serotonin receptors.', '5-20mg daily', 'Weight gain, hyperlipidemia, hyperglycemia, sedation, EPS (low), orthostatic hypotension', 4.5, '$$$$', 'Prescription only', 'Eli Lilly', 'Atypical Antipsychotic', 'C', 'Room temperature 20-25°C', '21-54 hours', '1-2 hours', '24 hours', 'Hepatic', 'Renal', 5432, 'CYP1A2 inhibitors,CYP3A4 inhibitors,CNS depressants', 'Weight gain, hyperlipidemia, hyperglycemia, monitor metabolic parameters', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Aripiprazole', 'Psychiatry', 'Aripiprazole is an atypical antipsychotic used for schizophrenia, bipolar disorder, and depression. It acts as a partial dopamine agonist.', '10-30mg daily', 'Akathisia, insomnia, weight gain (moderate), nausea, headache', 4.6, '$$$$', 'Prescription only', 'Bristol-Myers Squibb', 'Atypical Antipsychotic', 'C', 'Room temperature 20-25°C', '75 hours', '1-2 hours', '24 hours', 'Hepatic', 'Biliary', 6543, 'CYP3A4 inhibitors,CYP2D6 inhibitors,CNS depressants', 'Akathisia, insomnia, weight gain, monitor for EPS', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Lithium', 'Psychiatry', 'Lithium is a mood stabilizer used for bipolar disorder and depression. It modulates neurotransmitter release and signal transduction.', '300-600mg 2-3 times daily, extended release 900-1800mg once daily', 'Tremor, polyuria, polydipsia, GI upset, weight gain, hypothyroidism, renal impairment', 4.6, '$$', 'Prescription only', 'Various', 'Mood Stabilizer', 'D', 'Room temperature 20-25°C', '18-36 hours', '1-2 weeks', '24 hours', 'Renal', 'Renal', 8765, 'NSAIDs,Diuretics,ACE inhibitors,Antipsychotics', 'Narrow therapeutic index, monitor levels, renal impairment, hypothyroidism', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Lamotrigine', 'Psychiatry', 'Lamotrigine is an anticonvulsant and mood stabilizer used for bipolar depression and epilepsy. It blocks voltage-gated sodium channels.', '25-200mg daily, slow titration, max 400mg for epilepsy', 'Rash, Stevens-Johnson syndrome, headache, nausea, insomnia, dizziness', 4.7, '$$$', 'Prescription only', 'GlaxoSmithKline', 'Mood Stabilizer', 'C', 'Room temperature 20-25°C', '25-30 hours', '1-2 hours', '24 hours', 'Hepatic', 'Renal', 6543, 'Valproate,Carbamazepine,Phenytoin,Rifampin', 'Stevens-Johnson syndrome, slow titration, rash, monitor for hypersensitivity', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
