('Tapentadol', 'Pain Relief', 'Tapentadol is a centrally acting analgesic with dual mechanism: μ-opioid receptor agonism and norepinephrine reuptake inhibition. Used for moderate to severe pain.', '50-100mg every 4-6 hours, ER 50-250mg twice daily', 'Nausea, dizziness, constipation, sedation, serotonin syndrome, dependence', 4.4, '$$$$', 'Prescription only', 'Johnson & Johnson', 'Opioid Analgesic', 'C', 'Room temperature 20-25°C', '4 hours', '1-2 hours', '4-6 hours', 'Hepatic', 'Renal', 3456, 'SSRIs,SNRIs,MAOIs,Benzodiazepines,Alcohol', 'Serotonin syndrome, seizures, dependence, not for acute pain', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Flurbiprofen', 'Pain Relief', 'Flurbiprofen is an NSAID used for rheumatoid arthritis, osteoarthritis, and pain management. It has potent anti-inflammatory properties.', '50-100mg 2-3 times daily, max 300mg', 'GI upset, nausea, bleeding risk, cardiovascular risk, renal impairment', 4.3, '$$$', 'Prescription only', 'Pfizer', 'NSAID', 'D', 'Room temperature 20-25°C', '5-6 hours', '1-2 hours', '6-8 hours', 'Hepatic', 'Renal', 2345, 'Warfarin,Lithium,Methotrexate,ACE inhibitors', 'GI bleeding, cardiovascular risk, avoid in 3rd trimester', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Oxaprozin', 'Pain Relief', 'Oxaprozin is an NSAID used for osteoarthritis and rheumatoid arthritis. It has a long half-life allowing once-daily dosing.', '600-1200mg once daily', 'GI upset, nausea, dizziness, GI bleeding, cardiovascular risk', 4.2, '$$$', 'Prescription only', 'Pfizer', 'NSAID', 'D', 'Room temperature 20-25°C', '50 hours', '1-2 hours', '24 hours', 'Hepatic', 'Renal', 1234, 'Warfarin,Lithium,Methotrexate,ACE inhibitors', 'GI bleeding, cardiovascular risk, monitor renal function', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Mefenamic Acid', 'Pain Relief', 'Mefenamic acid is an NSAID used for mild to moderate pain, including dysmenorrhea. It has analgesic and anti-inflammatory properties.', '250-500mg every 6 hours, max 1500mg daily', 'GI upset, nausea, diarrhea, GI bleeding, renal impairment', 4.2, '$$', 'Prescription only', 'Pfizer', 'NSAID', 'D', 'Room temperature 20-25°C', '2-4 hours', '1-2 hours', '4-6 hours', 'Hepatic', 'Renal', 2345, 'Warfarin,Lithium,Methotrexate,ACE inhibitors', 'GI bleeding, renal impairment, avoid in children', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
