('Ceftriaxone', 'Antibiotics', 'Ceftriaxone is a third-generation cephalosporin antibiotic used for serious infections including meningitis, gonorrhea, and pneumonia. Inhibits bacterial cell wall synthesis.', '1-2g IV/IM once daily', 'Diarrhea, nausea, rash, allergic reactions, biliary sludging', 4.6, '$$$$', 'Prescription only', 'Roche', 'Cephalosporin', 'B', 'Room temperature 20-25°C', '5-10 hours', '1-2 hours', '24 hours', 'Hepatic', 'Renal', 4567, 'Warfarin,Metformin,Furosemide,Probenecid', 'Allergic reactions, biliary sludging, avoid in neonates with calcium', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Cefuroxime', 'Antibiotics', 'Cefuroxime is a second-generation cephalosporin antibiotic used for respiratory infections, skin infections, and Lyme disease. Inhibits bacterial cell wall synthesis.', '250-500mg twice daily, 750mg-1.5g IV', 'Diarrhea, nausea, rash, allergic reactions, C. difficile risk', 4.4, '$$$', 'Prescription only', 'GlaxoSmithKline', 'Cephalosporin', 'B', 'Room temperature 20-25°C', '1-2 hours', '1-2 hours', '12 hours', 'Hepatic', 'Renal', 3456, 'Warfarin,Metformin,Furosemide,Probenecid', 'Allergic reactions, diarrhea, C. difficile risk, renal adjustment', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
('Doxycycline Hyclate', 'Antibiotics', 'Doxycycline hyclate is a tetracycline antibiotic used for respiratory infections, acne, malaria prevention, and Lyme disease. It inhibits bacterial protein synthesis.', '100mg twice daily first day then 100mg once daily', 'Nausea, diarrhea, photosensitivity, teeth discoloration, esophagitis', 4.5, '$$', 'Prescription only', 'Pfizer', 'Tetracycline', 'D', 'Room temperature 20-25°C', '12-22 hours', '1-2 hours', '24 hours', 'Hepatic', 'Renal', 4321, 'Warfarin,Antacids,Calcium,Iron,Magnesium', 'Photosensitivity, teeth discoloration, esophagitis, take with water', 'https://images.unsplash.com/photo-1584308666744-24d5c474f2ae?w=300&h=300&fit=crop', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP),
